-        for (int c = 0; c < headers.length; c++) {
-            if ("Token".equalsIgnoreCase(headers[c].trim())) {
-                tokenColIdx = c;
-                break;
-            }
-        }
-        assertTrue(tokenColIdx >= 0, "Output CSV header must contain a 'Token' column");
